//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFGenericProcessToolCommand::MRFGenericProcessToolCommand() :
CATStateCommand ("MRFGenericProcessToolCommand", CATDlgEngOneShot, CATCommandModeExclusive)
, _pMRFGenericProcessToolsCmdDlg(NULL)
, _pPathElementAgentGeomSet(NULL)
, _pDialogAgentGeomSet(NULL)
, _pPatheElement(NULL)
, _pHSO(NULL)
, _pApplicationFrame(NULL)
, _spRootGeomSet(NULL_var)

//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
{
	_comboIndex = 0;
	_isEditMode = false;
	//-------------------------------------------------------------//
	_pApplicationFrame = CATApplicationFrame::GetFrame();
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
	}
}

//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFGenericProcessToolCommand::~MRFGenericProcessToolCommand()
{
	if (_pMRFGenericProcessToolsCmdDlg)
		_pMRFGenericProcessToolsCmdDlg->RequestDelayedDestruction(); _pMRFGenericProcessToolsCmdDlg = NULL;

	if (_pHSO)
	{
		_pHSO->Empty();
		_pHSO = NULL;
	}

	if (_pApplicationFrame)
		_pApplicationFrame = NULL;

	if (_pEditor)
		_pEditor = NULL;

	if (!!_pDialogAgentGeomSet)
		_pDialogAgentGeomSet->RequestDelayedDestruction(); _pDialogAgentGeomSet = NULL;

	if (!!_pPathElementAgentGeomSet)
		_pPathElementAgentGeomSet->RequestDelayedDestruction(); _pPathElementAgentGeomSet = NULL;

	if (!!_pPatheElement)
		_pPatheElement = NULL;
	
	if (!!_spRootGeomSet)
		_spRootGeomSet->Release(); _spRootGeomSet = NULL;

}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFGenericProcessToolCommand::BuildGraph()
{

	_pMRFGenericProcessToolsCmdDlg = new MRFGenericProcessToolsCmdDlg();
	if (_pMRFGenericProcessToolsCmdDlg)
	{
		CATUnicodeString baseNLSFileName = CmdHeader;
		baseNLSFileName.Append(".BaseNLS.Name");
		this->_baseNLSFileName = baseNLSFileName = CATMsgCatalog::BuildMessage(CmdHeader, baseNLSFileName.ConvertToChar());
		_pMRFGenericProcessToolsCmdDlg->Build(baseNLSFileName);
		_pMRFGenericProcessToolsCmdDlg->SetVisibility(CATDlgShow);

		AddAnalyseNotificationCB(_pMRFGenericProcessToolsCmdDlg, _pMRFGenericProcessToolsCmdDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFGenericProcessToolCommand::ActionOK, NULL);
		AddAnalyseNotificationCB(_pMRFGenericProcessToolsCmdDlg, _pMRFGenericProcessToolsCmdDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFGenericProcessToolCommand::ActionClose, NULL);
		AddAnalyseNotificationCB(_pMRFGenericProcessToolsCmdDlg, _pMRFGenericProcessToolsCmdDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFGenericProcessToolCommand::ActionClose, NULL);

		CATDlgCombo* pComboProcessTool = NULL;
		pComboProcessTool = _pMRFGenericProcessToolsCmdDlg->GetComboProcessTolType();
		if (pComboProcessTool)
		{
			AddAnalyseNotificationCB(pComboProcessTool, pComboProcessTool->GetComboSelectNotification(), (CATCommandMethod)& MRFGenericProcessToolCommand::onComBoProcessToolModified, NULL);
			AddAnalyseNotificationCB(pComboProcessTool, pComboProcessTool->GetComboModifyNotification(), (CATCommandMethod)& MRFGenericProcessToolCommand::onComBoProcessToolModified, NULL);

		}

		CATDlgCheckButton *pCheckButton = _pMRFGenericProcessToolsCmdDlg->GetRadioButtonEditMode();
		CATCommandClientData clientDataCheckButton = NULL;
		if (pCheckButton)
			clientDataCheckButton = pCheckButton;
		if (pCheckButton)
		{
			AddAnalyseNotificationCB(pCheckButton, pCheckButton->GetChkBModifyNotification(), (CATCommandMethod)& MRFGenericProcessToolCommand::OnCheckButtonModified,clientDataCheckButton);

		}

		_pPathElementAgentGeomSet = new CATPathElementAgent("GeomSet Sel PathElement Agent");
		if (_pPathElementAgentGeomSet)
		{
			_pPathElementAgentGeomSet->AddOrderedElementType("CATIBodyRequest");
			_pPathElementAgentGeomSet->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);
		}

		_pDialogAgentGeomSet = new CATDialogAgent("GeomSet Sel Agent");
		if (_pDialogAgentGeomSet)
		{
			CATDlgSelectorList* pGeomSet = _pMRFGenericProcessToolsCmdDlg->GetSelectorListGeomSet();
			if (pGeomSet)
			{
				_pDialogAgentGeomSet->AcceptOnNotify(pGeomSet, pGeomSet->GetListSelectNotification());

			}
		}


		// TODO: Define the StateChart
// ---------------------------

		CATDialogState *pGeomSetSelState = NULL;
		pGeomSetSelState = GetInitialState("GeomSet Select State");
		if (pGeomSetSelState)
		{
			pGeomSetSelState->AddDialogAgent(_pDialogAgentGeomSet);
			pGeomSetSelState->AddDialogAgent(_pPathElementAgentGeomSet);
		}

		CATDlgSelectorList* pGeomSetSelList = _pMRFGenericProcessToolsCmdDlg->GetSelectorListGeomSet();


		CATCommandClientData selListGeomSetLoc = NULL;
		if(pGeomSetSelList)
			selListGeomSetLoc  = pGeomSetSelList;
		
		AddTransition(pGeomSetSelState, pGeomSetSelState, IsOutputSetCondition(_pPathElementAgentGeomSet),
			Action((ActionMethod)&MRFGenericProcessToolCommand::OnObjectSelection, NULL, NULL, selListGeomSetLoc));

		//------------------------------------------For Selection Ends----------------------------------------------------------//

		//-----------For Transition Starts----------------//
		AddTransition(pGeomSetSelState, pGeomSetSelState, IsOutputSetCondition(_pDialogAgentGeomSet),
			Action((ActionMethod)&MRFGenericProcessToolCommand::OnSelectorListSelected, NULL, NULL, selListGeomSetLoc));



	}
}


