void MRFGenericProcessToolCommand::ActionClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	this->ExecuteUndoAtEnd();
	this->RequestDelayedDestruction();

	return;
}
//Function invoked when OK button is clicked
void MRFGenericProcessToolCommand::ActionOK(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (_isEditMode && _spRootGeomSet == NULL_var)
	{
		MRFGenericUtils::ShowErrorMessage("Can not launch process command \n Edit mode is selected and geometrical set is not selected \n Select Geometrical before starting or remove Edit mode ");
		return;
	}


	if (_pMRFGenericProcessToolsCmdDlg)
	{
		CATUnicodeString commonFileName = _baseNLSFileName, configFileName, strComboIndex, configFilePath, configFolderName;

		CATUnicodeString strProcessTooltype;
		if (_comboIndex != 0 && _spRootGeomSet && _isEditMode)
		{
			_pMRFGenericProcessToolsCmdDlg->GetComboProcessTolType()->GetLine(strProcessTooltype, _comboIndex);
			if (CheckUserSelectedProperGeomSetInEditMode(MRFGenericUtils::GetAliasName(_spRootGeomSet)) != true)
				MRFGenericUtils::ShowErrorMessage("Geometrical Set selected is different from choosen type, change Geometrical set or change the type");

		}

		if (_comboIndex)
		{
			strComboIndex.BuildFromNum(_comboIndex);
			commonFileName.Append(".");
			commonFileName.Append(strComboIndex);
			
			configFileName = commonFileName;
			configFilePath = commonFileName;
			configFolderName = commonFileName;

			configFileName.Append(".NLSConfigFileName");
			configFilePath.Append(".NLSConfigFilePath");
			configFolderName.Append(".NLSConfigFolderName");

			configFileName = CATMsgCatalog::BuildMessage(_baseNLSFileName.ConvertToChar(), configFileName.ConvertToChar());
			configFilePath = CATMsgCatalog::BuildMessage(_baseNLSFileName.ConvertToChar(), configFilePath.ConvertToChar());
			configFolderName = CATMsgCatalog::BuildMessage(_baseNLSFileName.ConvertToChar(), configFolderName.ConvertToChar());

			if (configFileName != "")
			{

				MRFProcessToolsCmd *pMRFProcessToolCmd = new MRFProcessToolsCmd(configFileName, configFolderName, _spRootGeomSet);
				this->RequestDelayedDestruction();
			}
		}
		else 
		{
			MRFGenericUtils::ShowErrorMessage("Select ProcessToolType ans click on OK");
		}


	}


	return;
}

//Function invoked when combo box is modified
void MRFGenericProcessToolCommand::onComBoProcessToolModified(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
 CATDlgCombo * pComboProcessToolType = NULL;
	pComboProcessToolType = _pMRFGenericProcessToolsCmdDlg->GetComboProcessTolType();
	if (pComboProcessToolType)
	{
		_comboIndex = pComboProcessToolType->GetSelect();
		CATUnicodeString strProcessTooltype;
		if (_comboIndex != 0 && _spRootGeomSet)
		{
			pComboProcessToolType->GetLine(strProcessTooltype, _comboIndex);
			if (CheckUserSelectedProperGeomSetInEditMode(MRFGenericUtils::GetAliasName(_spRootGeomSet)) != true)
				MRFGenericUtils::ShowErrorMessage("Geometrical Set selected is different from choosen type, change Geometrical set or change the type");

		}

	}
}
//Function is called when the Selector list is selected in dialog window
CATBoolean  MRFGenericProcessToolCommand::OnSelectorListSelected(void* iUsefulData)
{
	char *temp = (char*)iUsefulData;

	CATDlgSelectorList *pSelectorList = (CATDlgSelectorList *)iUsefulData;
	if (!pSelectorList)
		return FALSE;



	CATString selListName = pSelectorList->GetName();

	CATDialogAgent * pDialoAgent = NULL;
	CATPathElement * pPathElement = NULL;

	if (NULL != _pHSO)
	{
		_pHSO->Empty();
	}


	if (NULL != _pHSO)
	{

		if (NULL != _pPatheElement && 0 == _pHSO->IsMember(_pPatheElement))
		{
			_pHSO->AddElement(_pPatheElement);
		}

	}

	if (!!_pDialogAgentGeomSet)
		_pDialogAgentGeomSet->InitializeAcquisition();

	return TRUE;
}
//Function is called when the Geometrical Set object is selected in the tree
CATBoolean MRFGenericProcessToolCommand::OnObjectSelection(void* iUsefulData)
{
	if (_isEditMode == false)
	{
		MRFGenericUtils::ShowErrorMessage("Edit Mode is UnChecked, please check the edit mode for enabling Geometrical set selection");
		_pPathElementAgentGeomSet->InitializeAcquisition();
		return CATFalse;
	}

	char * pstrAction = (char *)iUsefulData;

	//CATString strAction(pstrAction);

	CATDlgSelectorList *pSelectorList = (CATDlgSelectorList *)iUsefulData;
	if (!pSelectorList)
		return FALSE;

	CATString selListName = pSelectorList->GetName();

	CATBaseUnknown_var spSelectedElement;
	CATPathElement * pPathElement = NULL;


	if (!!_pPathElementAgentGeomSet)
	{
		pPathElement = _pPathElementAgentGeomSet->GetValue();
		if (NULL != pPathElement)
		{
			_pPatheElement = pPathElement;

			CATUnicodeString strAlias = "";
			spSelectedElement = pPathElement->CurrentElement();

			if (!spSelectedElement)
				return FALSE;

			CATUnicodeString strName;
			CATIAlias_var spAlias = spSelectedElement;
			if (NULL_var != spAlias)
			{
				strName = spAlias->GetAlias();

				bool isProperGeomSetSelected = false;
				if (CheckUserSelectedProperGeomSetInEditMode(strName) && _isEditMode)
				{
					isProperGeomSetSelected = true;
					_pMRFGenericProcessToolsCmdDlg->UpdateSelectorList(strName);

				}
				else
				{
					_pMRFGenericProcessToolsCmdDlg->UpdateSelectorList("No Selection");
					if (_pPatheElement)
						_pPatheElement = NULL;

				}


					if (NULL_var != spSelectedElement)
					{
						if(isProperGeomSetSelected && _isEditMode)
							_spRootGeomSet = spSelectedElement;

						if (NULL != _pHSO)
						{
							_pHSO->Empty();

							if (0 == _pHSO->IsMember(pPathElement) && isProperGeomSetSelected && _isEditMode)
								_pHSO->AddElement(pPathElement);
						}
					}



			}

		}

		_pPathElementAgentGeomSet->InitializeAcquisition();
	}

	return CATTrue;
}

//Method called when the check box "edit mode" is clicked
void MRFGenericProcessToolCommand::OnCheckButtonModified(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData pCheckButton)
{
	CATDlgCheckButton *pDlgCheckButton = (CATDlgCheckButton*)pCheckButton;
	if (pCheckButton)
	{
		CATDlgSelectorList *pSelectorListGeomSet = _pMRFGenericProcessToolsCmdDlg->GetSelectorListGeomSet();

		if (pDlgCheckButton->GetState() == CATDlgCheck)
		{
			if (pSelectorListGeomSet)
				pSelectorListGeomSet->SetSensitivity(CATDlgEnable);
			
			_isEditMode = true;
		}
		else
		{
			if (pSelectorListGeomSet)
			{
				pSelectorListGeomSet->SetSensitivity(CATDlgDisable);
				pSelectorListGeomSet->ClearSelect();
				pSelectorListGeomSet->ClearLine();
			}

			_isEditMode = false;
			
			if (!!_spRootGeomSet)
				_spRootGeomSet->Release(); _spRootGeomSet = NULL;
			if (_pHSO)
				_pHSO->Empty();


		}
	}
}
//Checks if the selected geometrical set is correct or not
bool MRFGenericProcessToolCommand::CheckUserSelectedProperGeomSetInEditMode(CATUnicodeString selectedGeomSetName)
{
	CATDlgCombo* pComboProcesToolType = _pMRFGenericProcessToolsCmdDlg->GetComboProcessTolType();
	if (pComboProcesToolType)
	{
		if (_comboIndex == 0)
		{
			MRFGenericUtils::ShowErrorMessage("Choose the ProcessToolType and select the geometrical set");
			return false;
		}
		CATUnicodeString processToolTypeName;
		pComboProcesToolType->GetLine(processToolTypeName, _comboIndex);
		if (selectedGeomSetName == processToolTypeName)
			return true;
		else
		{
			MRFGenericUtils::ShowErrorMessage("Select the Correct ProcessToolType Geometrical Set");


		}
	}

	return false;

}